package be.schaubroeck.lpb.rkm.rekenmotor.voorbereiding;

import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ElektronischeVoorbereiding;
import be.schaubroeck.lpb.tools.ElektronischeVoorbereidingOpm;
import be.schaubroeck.lpb.tools.KalAfsluitenOpdracht;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.service.KalAfsluitenOpdrachtService;
import be.schaubroeck.lpb.tools.service.KalAfsluitenService;
import be.schaubroeck.lpb.tools.service.OpdrachtService;
import be.schaubroeck.temporal.interval.Month;
import be.schaubroeck.temporal.util.TemporalContext;
import lombok.AllArgsConstructor;

import java.util.ArrayList;
import java.util.Collection;
import java.util.List;
import java.util.Set;

@AllArgsConstructor
public class RekenVoorbereidingFactory {

    private final KalAfsluitenOpdrachtService kalAfsluitenOpdrachtService;
    private final OpdrachtService opdrachtService;
    private final KalAfsluitenService kalAfsluitenService;

    public List<RekenVoorbereiding> create(Admin admin, Collection<ElektronischeVoorbereiding> voorbereidingen) {
        List<RekenVoorbereiding> rekenVoorbereidingen = new ArrayList<>();
        for (ElektronischeVoorbereiding voorbereiding : voorbereidingen) {
            rekenVoorbereidingen.add(create(admin, voorbereiding));
        }
        return rekenVoorbereidingen;
    }

    public RekenVoorbereiding create(Admin admin, ElektronischeVoorbereiding voorbereiding) {
        boolean isKalenderOpdracht = isKalenderOpdracht(voorbereiding);
        Opdracht opdracht = null;
        int kalAfsluitenOpdrachtId = 0;
        if (isKalenderOpdracht) {
            kalAfsluitenOpdrachtId = bepaalKalAfsluitenOpdrachtId(admin, voorbereiding);
            opdracht = findKalenderVoorbereidingOpdracht(admin, voorbereiding, kalAfsluitenOpdrachtId);
        }
        int kalAfsluitenId = bepaalKalAfsluitenId(admin, voorbereiding);

        return RekenVoorbereiding.builder()
                .elektronischeVoorbereiding(voorbereiding)
                .admin(admin)
                .isKalenderOpdracht(isKalenderOpdracht)
                .kalAfsluitenOpdrachtId(kalAfsluitenOpdrachtId)
                .opdracht(opdracht)
                .kalAfsluitenId(kalAfsluitenId)
                .kalAfsluitenService(kalAfsluitenService)
                .opdrachtService(opdrachtService)
                .build();
    }

    private boolean isKalenderOpdracht(ElektronischeVoorbereiding voorbereiding) {
        Set<ElektronischeVoorbereidingOpm> opmerkingen = voorbereiding.getOpmerkingen();
        for (ElektronischeVoorbereidingOpm opm : opmerkingen) {
            if (opm.getTekst().contentEquals("opdracht")) {
                return true;
            }
        }
        return false;
    }

    private Opdracht findKalenderVoorbereidingOpdracht(Admin admin, ElektronischeVoorbereiding voorbereiding, int kalAfsluitenOpdrachtId) {
        TemporalContext temporalContext = TemporalContext.getInstance();
        temporalContext.setActualInterval(new Month(voorbereiding.getJaar(), voorbereiding.getMaand()));
        KalAfsluitenOpdracht kalAfsluitenOpdracht = kalAfsluitenOpdrachtService.getById(admin, kalAfsluitenOpdrachtId, "opdracht{persoon{persoonSlices}}");
        temporalContext.clearActualInterval();

        return kalAfsluitenOpdracht.getOpdracht();
    }

    private int bepaalKalAfsluitenOpdrachtId(Admin admin, ElektronischeVoorbereiding voorbereiding) {
        String adminid = String.valueOf(admin.getId());
        String vbid = String.valueOf(voorbereiding.getVoorbereidingId());
        return Integer.parseInt(vbid.substring(adminid.length())) - 100000;
    }

    public int bepaalKalAfsluitenId(Admin admin, ElektronischeVoorbereiding voorbereiding) {
        return bepaalKalAfsluitenId(admin.getId(), voorbereiding.getVoorbereidingId());
    }

    public static int bepaalKalAfsluitenId(Integer adminId, Integer voorbereidingId) {
        String adminid = String.valueOf(adminId);
        String vbid = String.valueOf(voorbereidingId);
        return Integer.parseInt(vbid.substring(adminid.length() + 1));
    }
}
